import{c as n,S as h,j as a,m as t}from"./chunks/framework.8aa1YH_s.js";const p=JSON.parse('{"title":"Hỏi đáp (Giáo viên)","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/hoi-dap.md","filePath":"giao-vien/hoi-dap.md","lastUpdated":0}'),c={name:"giao-vien/hoi-dap.md"};function l(o,i,r,u,e,g){return h(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="hoi-đap-giao-vien" tabindex="-1">Hỏi đáp (Giáo viên) <a class="header-anchor" href="#hoi-đap-giao-vien" aria-label="Permalink to “Hỏi đáp (Giáo viên)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/reply</code></p><p>Học viên đặt câu hỏi từ các vị trí trong khóa của bạn (dưới bài giảng, sau câu hỏi đề thi sai, hoặc trong khu thảo luận khóa). Tất cả câu hỏi đó tập trung tại đây.</p><h2 id="danh-sach-cau-hoi" tabindex="-1">Danh sách câu hỏi <a class="header-anchor" href="#danh-sach-cau-hoi" aria-label="Permalink to “Danh sách câu hỏi”">​</a></h2><p>Cột chính:</p><ul><li>Học viên (tên, SĐT)</li><li>Tiêu đề / trích nội dung câu hỏi</li><li>Vị trí: khóa / bài giảng / câu hỏi đề thi cụ thể</li><li>Trạng thái (Chưa trả lời / Đã trả lời / Đã đóng)</li><li>Thời gian gửi</li><li>Số phản hồi qua lại</li></ul><h2 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h2><ul><li><strong>Trạng thái</strong> (mặc định lọc &quot;Chưa trả lời&quot; để bạn xử lý trước)</li><li><strong>Khóa học / Bài giảng</strong></li><li><strong>Khoảng thời gian</strong></li><li><strong>Tìm kiếm</strong> trong nội dung</li></ul><h2 id="mo-chi-tiet-tra-loi" tabindex="-1">Mở chi tiết &amp; trả lời <a class="header-anchor" href="#mo-chi-tiet-tra-loi" aria-label="Permalink to “Mở chi tiết &amp; trả lời”">​</a></h2><p><code>https://lamsonedutech.vn/teacher/detail-reply/:idReply</code></p><ol><li>Bấm vào câu hỏi.</li><li>Đọc nội dung (kèm hình ảnh, file đính kèm nếu có).</li><li>Mở <strong>bài giảng / câu hỏi đề thi liên quan</strong> trong tab mới để tra cứu.</li><li>Gõ phản hồi: <ul><li>Rich text: định dạng, công thức (LaTeX), code, link</li><li>Đính kèm ảnh / file (vd: scan giải bài tay)</li><li>Có thể đính kèm video ngắn explainer (nếu hệ thống cho phép)</li></ul></li><li>Bấm <strong>Gửi</strong>.</li></ol><p>Học viên nhận thông báo và có thể hỏi tiếp.</p><h2 id="đong-cau-hoi" tabindex="-1">Đóng câu hỏi <a class="header-anchor" href="#đong-cau-hoi" aria-label="Permalink to “Đóng câu hỏi”">​</a></h2><ul><li>Khi giải đáp xong, bấm <strong>Đóng</strong>.</li><li>Câu hỏi vẫn lưu trữ cho học viên khác xem (nếu công khai).</li></ul><h2 id="đanh-dau-cau-hoi-huu-ich-pin" tabindex="-1">Đánh dấu câu hỏi hữu ích / pin <a class="header-anchor" href="#đanh-dau-cau-hoi-huu-ich-pin" aria-label="Permalink to “Đánh dấu câu hỏi hữu ích / pin”">​</a></h2><ul><li>Bấm icon <strong>Pin / Đánh dấu hữu ích</strong> để câu hỏi xuất hiện đầu danh sách thảo luận của khóa.</li><li>Hữu ích khi câu hỏi/đáp này là <strong>kiến thức mà nhiều học viên cùng cần</strong>.</li></ul><h2 id="chuyen-cau-hoi-khong-lien-quan" tabindex="-1">Chuyển câu hỏi không liên quan <a class="header-anchor" href="#chuyen-cau-hoi-khong-lien-quan" aria-label="Permalink to “Chuyển câu hỏi không liên quan”">​</a></h2><p>Nếu câu hỏi nằm ngoài chuyên môn của bạn:</p><ul><li>Bấm <strong>Báo Admin</strong> → admin sẽ điều hướng.</li><li>Hoặc viết &quot;câu này tôi sẽ nhờ giáo viên X phụ trách giải đáp&quot; và đợi admin chuyển.</li></ul><h2 id="meo-tra-loi-nhanh-chat-luong" tabindex="-1">Mẹo trả lời nhanh &amp; chất lượng <a class="header-anchor" href="#meo-tra-loi-nhanh-chat-luong" aria-label="Permalink to “Mẹo trả lời nhanh &amp; chất lượng”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Tách thành nhiều bước</p><p>Đáp án dài hãy chia thành các bước/số mục để học viên dễ theo dõi.</p></div><div class="tip custom-block"><p class="custom-block-title">Đính kèm hình giải tay</p><p>Có khi 1 bức ảnh giải tay rõ hơn 200 từ. Chụp giấy nháp, đính kèm.</p></div><div class="tip custom-block"><p class="custom-block-title">Tránh sao chép nguyên đáp án từ tài liệu</p><p>Học viên hỏi vì chưa hiểu - cần lời giải bám sát chỗ học viên vướng, không chỉ copy lời giải mẫu.</p></div><div class="warning custom-block"><p class="custom-block-title">Tránh phản hồi quá ngắn</p><p>&quot;Đáp án B em nhé&quot; là không đủ - học viên không học được gì. Hãy giải thích <strong>vì sao</strong>.</p></div><h2 id="theo-doi-sla" tabindex="-1">Theo dõi SLA <a class="header-anchor" href="#theo-doi-sla" aria-label="Permalink to “Theo dõi SLA”">​</a></h2><ul><li>Đặt mục tiêu phản hồi <strong>trong 24 giờ làm việc</strong>.</li><li>Mở Dashboard hằng ngày, ưu tiên câu chưa trả lời.</li><li>Nếu bận, nhờ trợ giảng (nếu có) hoặc Admin hỗ trợ.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên hỏi cùng 1 câu nhiều lần?</strong> → Trả lời 1 lần đầy đủ rồi <strong>Pin</strong> lên đầu khu thảo luận. Lần sau chỉ cần dẫn link.</p><p><strong>Học viên gửi câu hỏi spam / quảng cáo?</strong> → Báo Admin để khóa câu hỏi và xử lý tài khoản.</p><p><strong>Tôi muốn trả lời tất cả câu hỏi của 1 chuyên đề cùng lúc?</strong> → Lọc theo chuyên đề + sắp xếp theo thời gian. Trả lời lần lượt, dùng template phản hồi nếu nhiều câu giống nhau.</p>',30)])])}const d=n(c,[["render",l]]);export{p as __pageData,d as default};
